@SpringBootApplication
public class KafkaProducerApplication {
    public static void main(String[] args) {
        SpringApplication.run(KafkaProducerApplication.class, args);
    }

    @Bean
    public KafkaProducer<String, String> kafkaProducer() {
        Properties props = new Properties();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.ACKS_CONFIG, "all");
        props.put(ProducerConfig.RETRIES_CONFIG, 3);
        props.put(ProducerConfig.LINGER_MS_CONFIG, 1);
        return new KafkaProducer<>(props);
    }
}

@RestController
@RequestMapping("/api/events")
class EventController {
    
    private final KafkaProducer<String, String> kafkaProducer;
    private static final String TOPIC = "event-tracking";

    public EventController(KafkaProducer<String, String> kafkaProducer) {
        this.kafkaProducer = kafkaProducer;
    }

    @PostMapping("/send")
    public ResponseEntity<EventResponse> sendEvent(@RequestBody EventRequest request) {
        try {
            ProducerRecord<String, String> record = createProducerRecord(request);
            RecordMetadata metadata = kafkaProducer.send(record).get();
            
            EventResponse response = new EventResponse(
                true,
                "Event sent successfully",
                metadata.topic(),
                metadata.partition(),
                metadata.offset(),
                extractHeaders(record)
            );
            
            return ResponseEntity.ok(response);
        } catch (InterruptedException | ExecutionException e) {
            return ResponseEntity.internalServerError()
                .body(new EventResponse(false, "Failed to send event: " + e.getMessage(), null, -1, -1L, null));
        }
    }

    @PostMapping("/send-async")
    public ResponseEntity<Map<String, String>> sendEventAsync(@RequestBody EventRequest request) {
        ProducerRecord<String, String> record = createProducerRecord(request);
        
        kafkaProducer.send(record, new Callback() {
            @Override
            public void onCompletion(RecordMetadata metadata, Exception exception) {
                if (exception != null) {
                    System.err.println("Error sending event: " + exception.getMessage());
                } else {
                    System.out.println("Event sent to topic: " + metadata.topic() + 
                        ", partition: " + metadata.partition() + 
                        ", offset: " + metadata.offset());
                }
            }
        });
        
        Map<String, String> response = new HashMap<>();
        response.put("status", "accepted");
        response.put("message", "Event queued for sending");
        return ResponseEntity.accepted().body(response);
    }

    @PostMapping("/batch")
    public ResponseEntity<BatchEventResponse> sendBatchEvents(@RequestBody BatchEventRequest request) {
        List<EventResult> results = new ArrayList<>();
        
        for (EventRequest eventRequest : request.getEvents()) {
            try {
                ProducerRecord<String, String> record = createProducerRecord(eventRequest);
                RecordMetadata metadata = kafkaProducer.send(record).get();
                results.add(new EventResult(true, metadata.offset(), null));
            } catch (Exception e) {
                results.add(new EventResult(false, -1L, e.getMessage()));
            }
        }
        
        long successCount = results.stream().filter(EventResult::isSuccess).count();
        BatchEventResponse response = new BatchEventResponse(
            successCount,
            results.size() - successCount,
            results
        );
        
        return ResponseEntity.ok(response);
    }

    private ProducerRecord<String, String> createProducerRecord(EventRequest request) {
        String topic = request.getTopic() != null ? request.getTopic() : TOPIC;
        String key = request.getKey();
        String value = request.getMessage();
        
        List<Header> headers = new ArrayList<>();
        
        if (request.getTrackingId() != null) {
            headers.add(new RecordHeader("tracking-id", request.getTrackingId().getBytes(StandardCharsets.UTF_8)));
        }
        
        if (request.getUserId() != null) {
            headers.add(new RecordHeader("user-id", request.getUserId().getBytes(StandardCharsets.UTF_8)));
        }
        
        if (request.getHeaders() != null) {
            for (Map.Entry<String, String> entry : request.getHeaders().entrySet()) {
                headers.add(new RecordHeader(entry.getKey(), entry.getValue().getBytes(StandardCharsets.UTF_8)));
            }
        }
        
        headers.add(new RecordHeader("timestamp", String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8)));
        headers.add(new RecordHeader("source", "event-tracking-api".getBytes(StandardCharsets.UTF_8)));
        
        ProducerRecord<String, String> record = new ProducerRecord<>(topic, null, key, value, headers);
        return record;
    }

    private Map<String, String> extractHeaders(ProducerRecord<String, String> record) {
        Map<String, String> headerMap = new HashMap<>();
        for (Header header : record.headers()) {
            headerMap.put(header.key(), new String(header.value(), StandardCharsets.UTF_8));
        }
        return headerMap;
    }
}

